module B(
    input m,
    input n,
    output z
);
    assign z = (m | n);
endmodule

module top_module(
    input m,
    input n,
    output z
);
    wire a1_out, a2_out, a3_out, b_out;
    wire nor_out, and_out;

    A a1(.m(m), .n(n), .z(a1_out));
    A a2(.m(m), .n(n), .z(a2_out));
    A a3(.m(m), .n(n), .z(a3_out));
    B b1(.m(m), .n(n), .z(b_out));

    assign nor_out = ~(a1_out | b_out);
    assign and_out = a2_out & a3_out;

    assign z = nor_out ^ and_out;
endmodule
